compliant:
public class MyClass
{
    private static List<MyClass> instances = new List<MyClass>();

    public MyClass() { }

    public static MyClass Create()
    {
        var instance = new MyClass();
        instances.Add(instance); // Compliant - object fully constructed
        return instance;
    }
}

public class Publisher
{
    public event EventHandler MyEvent;

    public Publisher() { }

    public void Initialize(EventHandler handler)
    {
        MyEvent += handler;
        handler(this, EventArgs.Empty); // Compliant - not in constructor
    }
}
